341: // syncWatchers syncs unsynced watchers by:
342: //  1. choose a set of watchers from the unsynced watcher group
343: //  2. iterate over the set to get the minimum revision and remove compacted watchers
344: //  3. use minimum revision to get all key-value pairs and send those events to watchers
345: //  4. remove synced watchers in set from unsynced group and move to synced group
346: func (s *watchableStore) syncWatchers(evs []mvccpb.Event) (int, []mvccpb.Event) {
347: 	s.mu.Lock()
348: 	defer s.mu.Unlock()
349: 
350: 	if s.unsynced.size() == 0 {
351: 		return 0, []mvccpb.Event{}
352: 	}
353: 
354: 	s.store.revMu.RLock()
355: 	defer s.store.revMu.RUnlock()
356: 
357: 	// in order to find key-value pairs from unsynced watchers, we need to
358: 	// find min revision index, and these revisions can be used to
359: 	// query the backend store of key-value pairs
360: 	curRev := s.store.currentRev
361: 	compactionRev := s.store.compactMainRev
362: 
363: 	wg, minRev := s.unsynced.choose(maxWatchersPerSync, curRev, compactionRev)
364: 	evs = rangeEventsWithReuse(s.store.lg, s.store.b, evs, minRev, curRev+1)
365: 
366: 	victims := make(watcherBatch)
367: 	wb := newWatcherBatch(wg, evs)
368: 	for w := range wg.watchers {
369: 		if w.minRev < compactionRev {
370: 			// Skip the watcher that failed to send compacted watch response due to w.ch is full.
371: 			// Next retry of syncWatchers would try to resend the compacted watch response to w.ch
372: 			continue
373: 		}
374: 		w.minRev = max(curRev+1, w.minRev)
375: 
