237: func (wg *watcherGroup) chooseAll(curRev, compactRev int64) int64 {
238: 	minRev := int64(math.MaxInt64)
239: 	for w := range wg.watchers {
240: 		if w.minRev > curRev {
241: 			// after network partition, possibly choosing future revision watcher from restore operation
242: 			// with watch key "proxy-namespace__lostleader" and revision "math.MaxInt64 - 2"
243: 			// do not panic when such watcher had been moved from "synced" watcher during restore operation
244: 			if !w.restore {
245: 				panic(fmt.Errorf("watcher minimum revision %d should not exceed current revision %d", w.minRev, curRev))
246: 			}
247: 
248: 			// mark 'restore' done, since it's chosen
249: 			w.restore = false
250: 		}
251: 		if w.minRev < compactRev {
252: 			select {
253: 			case w.ch <- WatchResponse{WatchID: w.id, CompactRevision: compactRev}:
254: 				w.compacted = true
255: 				wg.delete(w)
256: 			default:
257: 				// retry next time
258: 			}
259: 			continue
260: 		}
261: 		if minRev > w.minRev {
262: 			minRev = w.minRev
263: 		}
264: 	}
265: 	return minRev
266: }
